--
-- Table structure for table `t075t_division_types`
--

DROP TABLE IF EXISTS `t075t_division_types`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `t075t_division_types` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'Consecutivo único del registro',
  `code` varchar(32) NOT NULL COMMENT 'Código interno de la división',
  `id_country` int NOT NULL COMMENT 'Identificador del país',
  `id_level_type` int NOT NULL COMMENT 'Identificador del nivel de división',
  `name_spanish` varchar(128) NOT NULL COMMENT 'Nombre del tipo geográfico en español',
  `name_english` varchar(128) NOT NULL COMMENT 'Nombre del tipo geográfico en inglés',
  `name_iso` varchar(128) NOT NULL COMMENT 'Nombre oficial ISO del tipo geográfico',
  `name_original` varchar(128) NOT NULL COMMENT 'Nombre del tipo geográfico en idioma oficial',
  `name_transcribed` varchar(128) NOT NULL COMMENT 'Nombre del tipo geográfico transcrito a alfabeto latino legible',
  `status` int NOT NULL DEFAULT '1' COMMENT 'Estado del registro: 1=activo, 0=inactivo',
  `created_at` datetime(6) NOT NULL COMMENT 'Fecha y hora de creación del registro',
  `updated_at` datetime(6) NOT NULL COMMENT 'Fecha y hora de última actualización del registro',
  `created_by` int NOT NULL COMMENT 'Usuario que creó el registro',
  `updated_by` int NOT NULL COMMENT 'Usuario que realizó la última actualización del registro',
  PRIMARY KEY (`id`),
  UNIQUE KEY `UK_t075t_code` (`code`),
  KEY `FK_t075t_id_country_t074t` (`id_country`),
  KEY `FK_t075t_id_level_type_t070t` (`id_level_type`),
  CONSTRAINT `FK_t075t_id_country_t074t` FOREIGN KEY (`id_country`) REFERENCES `t074t_countries` (`id`),
  CONSTRAINT `FK_t075t_id_level_type_t070t` FOREIGN KEY (`id_level_type`) REFERENCES `t070t_level_types` (`id`),
  CONSTRAINT `CHK_NE_t075t_code` CHECK ((`code` <> _utf8mb4'')),
  CONSTRAINT `CHK_NE_t075t_name_english` CHECK ((`name_english` <> _utf8mb4'')),
  CONSTRAINT `CHK_NE_t075t_name_spanish` CHECK ((`name_spanish` <> _utf8mb4''))
) ENGINE=InnoDB AUTO_INCREMENT=261 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Tipificación de divisiones geográficas: departamento, municipio, barrio, etc.';
/*!40101 SET character_set_client = @saved_cs_client */;

